import type { CSSProperties } from "react";

// Company logos — base64-encoded images keyed by company ID.
// Transparent PNGs work on both dark and light backgrounds.

export const COMPANY_LOGOS: Record<string, string> = {
  nintendo: "data:image/png;base64,",
  sony: "data:image/png;base64,",
  microsoft: "data:image/jpeg;base64,",
  sega: "data:image/png;base64,",
  commodore: "data:image/png;base64,",
  atari: "data:image/png;base64,",
  coleco: "data:image/png;base64,",
  philips: "data:image/png;base64,",
  snk: "data:image/png;base64,",
};

/** Alias — same images work on both themes */
export const COMPANY_LOGOS_DARK = COMPANY_LOGOS;

/** Per-company img style overrides. dark/light keys optional. */
export const COMPANY_LOGO_STYLES: Record<string, { dark?: CSSProperties; light?: CSSProperties }> = {
  microsoft: {
    dark:  { background: 'white', borderRadius: 6, padding: '3px 8px' },
    light: { background: 'white', borderRadius: 6, padding: '3px 8px' },
  },
  commodore: {
    dark:  { filter: 'invert(1) brightness(1.4)' },
  },
};
